package Loop;
import java.util.*;

public class PrintNoNto1 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		Scanner sc = new Scanner(System.in);
		System.out.println("enter value of n :");
		int n = sc.nextInt();
		for(int i=n; i>=1; i--) {
			System.out.println(i);
		}

	}

}
